mapper.select:
SELECT c.id as courseId, c.name, c.description, c.cover_image as coverImage, c.teacher_name as teacherName, c.chapter_count as chapterCount, c.student_count as studentCount, c.create_time as createTime, s.name as subjectName, g.name as gradeName FROM course c LEFT JOIN subject s ON c.subject_id = s.id LEFT JOIN grade g ON c.grade_id = g.id WHERE c.is_deleted = 0
AND c.subject_id = #{subjectId}
AND c.grade_id = #{gradeId}
AND (c.name LIKE CONCAT('%', #{keyword}, '%') OR c.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.create_time DESC
